function compressPhoto(dataURL) {
  return new Promise(function(resolve) {
    var img = new Image();
    img.onload = function() {
      var c = document.createElement('canvas');
      c.width = 400; c.height = 600;
      var ratio = Math.min(400 / img.width, 600 / img.height);
      var w = img.width * ratio, h = img.height * ratio;
      var ctx = c.getContext('2d');
      ctx.fillStyle = '#000';
      ctx.fillRect(0, 0, 400, 600);
      ctx.drawImage(img, (400 - w) / 2, (600 - h) / 2, w, h);
      resolve(c.toDataURL('image/jpeg', 0.8));
    };
    img.onerror = function() { resolve(null); };
    img.src = dataURL;
  });
}

function cleanOldPhotosIfFull(force) {
  try {
    var total = 0;
    for (var i = 0; i < localStorage.length; i++) { total += (localStorage.getItem(localStorage.key(i)) || '').length; }
    if (!force && total < 4 * 1024 * 1024) return;
    // 1. Purge verset_cache au-delà de 50
    var _vcKeys = [];
    for (var k = 0; k < localStorage.length; k++) { var _kn = localStorage.key(k); if (_kn && _kn.indexOf('verset_cache_') === 0) _vcKeys.push(_kn); }
    if (_vcKeys.length > 50) { _vcKeys.sort(); var _toRemove = _vcKeys.slice(0, _vcKeys.length - 50); _toRemove.forEach(function(rk) { localStorage.removeItem(rk); }); }
    // 2. Purge photos 20 par 20, plus anciennes d'abord, max 5 passes
    var _purged = 0;
    for (var _pass = 0; _pass < 5; _pass++) {
      total = 0;
      for (var ii = 0; ii < localStorage.length; ii++) { total += (localStorage.getItem(localStorage.key(ii)) || '').length; }
      if (total < 4 * 1024 * 1024) break;
      var _batchDone = false;
      ['niyyah_regarde_history', 'niyyah_niyyah_history'].forEach(function(key) {
        if (_batchDone) return;
        var arr; try { arr = JSON.parse(localStorage.getItem(key) || '[]'); } catch(e) { arr = []; }
        var count = 0;
        for (var j = 0; j < arr.length && count < 20; j++) {
          if (arr[j].photo) { arr[j].photo = null; count++; _purged++; }
        }
        if (count > 0) { localStorage.setItem(key, JSON.stringify(arr)); _batchDone = true; }
      });
      if (!_batchDone) break;
    }
    if (_purged > 0 && typeof showToast === 'function') showToast(_purged + ' photo' + (_purged > 1 ? 's' : '') + ' archiv\u00e9e' + (_purged > 1 ? 's' : '') + ' \u2014 m\u00e9moire lib\u00e9r\u00e9e');
  } catch(e) {}
}

var _journalCache = { niyyah_niyyah_history: null, niyyah_regarde_history: null };
function _journalGet(key) {
  if (_journalCache[key] !== undefined && _journalCache[key] !== null) return _journalCache[key];
  try { var arr = JSON.parse(localStorage.getItem(key) || '[]'); _journalCache[key] = arr; return arr; } catch(e) { return []; }
}

function _journalSave(key, arr) {
  cleanOldPhotosIfFull();
  _journalCache[key] = arr;
  if (!safeSetItem(key, JSON.stringify(arr))) {
    if (typeof showToast === 'function') showToast('Sauvegarde impossible \u2014 lib\u00e9rez de l\u2019espace');
  }
}

function addRegardeEntry(entry) {
  var arr = _journalGet('niyyah_regarde_history');
  var item = {
    id: Date.now() + '_' + Math.random().toString(36).slice(2, 6),
    date: new Date().toISOString(),
    question: entry.question || '',
    category: entry.category || 'INDETERMINE',
    verset_index: typeof entry.verset_index === 'number' ? entry.verset_index : undefined,
    photo: entry.photo || null,
    bookmark: !!entry.bookmark,
    note: entry.note || ''
  };
  if (item.photo && localStorage.getItem('niyyah_photo_disclaimer_seen') !== '1') {
    safeSetItem('niyyah_photo_disclaimer_seen', '1');
    if (typeof showToast === 'function') setTimeout(function() { showToast(t('photo_disclaimer'), 5000); }, 500);
  }
  arr.unshift(item);
  _journalSave('niyyah_regarde_history', arr);
  return item;
}

function addNiyyahEntry(entry) {
  var arr = _journalGet('niyyah_niyyah_history');
  var item = {
    id: Date.now() + '_' + Math.random().toString(36).slice(2, 6),
    date: new Date().toISOString(),
    intention: entry.intention || '',
    category: entry.category || 'INDETERMINE',
    photo: entry.photo || null
  };
  arr.unshift(item);
  _journalSave('niyyah_niyyah_history', arr);
  return item;
}

function getRegardeHistory() { return _journalGet('niyyah_regarde_history'); }
function getNiyyahHistory() { return _journalGet('niyyah_niyyah_history'); }

function updateRegardeEntry(id, updates) {
  var arr = _journalGet('niyyah_regarde_history');
  for (var i = 0; i < arr.length; i++) {
    if (arr[i].id === id) {
      if (updates.bookmark !== undefined) arr[i].bookmark = updates.bookmark;
      if (updates.note !== undefined) arr[i].note = updates.note;
      _journalSave('niyyah_regarde_history', arr);
      return arr[i];
    }
  }
  return null;
}

function deleteEntry(type, id) {
  var key = type === 'regarde' ? 'niyyah_regarde_history' : 'niyyah_niyyah_history';
  var arr = _journalGet(key);
  arr = arr.filter(function(e) { return e.id !== id; });
  _journalSave(key, arr);
}

function migrateOldJournal() {
  if (localStorage.getItem('niyyah_migration_v2_done') === '1') return;
  try {
    var old = safeParseJSON('niyyah_scanner_history', []);
    if (old.length > 0) {
      var existing = _journalGet('niyyah_niyyah_history');
      old.forEach(function(entry) {
        existing.push({
          id: (entry.date || '') + '_' + Math.random().toString(36).slice(2, 6),
          date: entry.date ? new Date(entry.date + 'T' + (entry.time || '00:00')).toISOString() : new Date().toISOString(),
          intention: entry.text || '',
          category: 'INDETERMINE',
          photo: null
        });
      });
      if (safeSetItem('niyyah_niyyah_history', JSON.stringify(existing))) {
        safeSetItem('niyyah_migration_v2_done', '1');
      }
    } else {
      safeSetItem('niyyah_migration_v2_done', '1');
    }
  } catch(e) {}
}
migrateOldJournal();

