    + '<div style="font-size:13px;font-style:italic;color:rgba(200,168,75,0.5);line-height:1.6;margin-bottom:16px;">\u00ab\u00a0Ton corps a un droit sur toi.\u00a0\u00bb \u2014 Bukh\u00e2r\u00ee 1968</div>'
