    + '<div class="itfaa-body" style="font-size:14px;font-style:italic;line-height:1.6;margin-bottom:6px;">\u00ab\u00a0All\u00e2h ne charge aucune \u00e2me au-del\u00e0 de sa capacit\u00e9.\u00a0\u00bb</div>'
