function _itfaaDepistageEncart() {
  var el = document.getElementById('babAnNafsContent');
  if (!el) { renderBabAnNafs(); return; }
  var c = '#B33A3A';
  el.innerHTML = '<div style="padding:calc(var(--safe-top)+60px) 16px 120px;max-width:600px;margin:0 auto;text-align:center;">'
    + '<div style="border:1px solid #a3372a;border-radius:14px;padding:14px;max-width:480px;margin:0 auto 28px;background:#0a0a0a;text-align:center;">'
    + '<div style="font-size:15px;color:#E5E0DC;line-height:1.6;">Tu as utilis\u00e9 l\u2019I\u1e6df\u00e2\u2019 Shad\u00eed 5\u00a0fois en 2\u00a0semaines. Cette fr\u00e9quence m\u00e9rite un avis m\u00e9dical pour v\u00e9rifier qu\u2019il n\u2019y a pas de cause sous-jacente (trouble explosif, d\u00e9pression, autre).</div>'
    + '</div>'
    + '<div style="display:flex;flex-direction:column;gap:12px;max-width:340px;margin:0 auto;">'
    + '<button onclick="safeSetItem(\'itfaa_depistage_vu\',String(Date.now()));_cureDepistage()" style="width:100%;padding:14px;border-radius:12px;border:none;background:#a3372a;color:#fff;font-size:14px;font-weight:600;font-family:var(--serif);cursor:pointer;">Faire le d\u00e9pistage</button>'
    + '<button onclick="safeSetItem(\'itfaa_depistage_vu\',String(Date.now()));_babImmersion=false;_hideAideBtn();var _nb=document.getElementById(\'nav-bar-v2\');if(_nb)_nb.classList.remove(\'hidden-immersion\');v2GoSanctuaire()" style="width:100%;padding:14px;border-radius:12px;border:1px solid rgba(200,168,75,0.2);background:none;color:rgba(200,168,75,0.5);font-family:var(--serif);font-size:14px;cursor:pointer;">Plus tard</button>'
    + '</div></div>';
}

function babCompletPorte(id) {
  try {
    var data = JSON.parse(safeGetItem('niyyah_bab_an_nafs') || '{}');
    if (!data[id]) data[id] = { count: 0 };
    data[id].count = (data[id].count || 0) + 1;
    data[id].lastDate = todayKey();
    safeSetItem('niyyah_bab_an_nafs', JSON.stringify(data));
    // Rotate content index for next visit
    var idx = _babGetIdx(id);
    var porte = BAB_AN_NAFS.portes.find(function(p) { return p.id === id; });
    if (porte) {
      idx.rappel = (idx.rappel + 1) % (porte.rappels || [0]).length;
      idx.action = (idx.action + 1) % (porte.actions || [0]).length;
      idx.intention = (idx.intention + 1) % (porte.intentions || [0]).length;
      idx.cloture = (idx.cloture + 1) % (porte.clotures || [0]).length;
      _babSetIdx(id, idx);
    }
  } catch(e) {}
  // Détection colère pathologique (>= 5 parcours en 7 jours)
  if (id === 'colere') {
    try {
      var completions = JSON.parse(safeGetItem('colere_completions') || '[]');
      completions.push(Date.now());
      // Garder uniquement les 30 derniers jours
      var cutoff30d = Date.now() - 30 * 86400000;
      completions = completions.filter(function(t) { return t > cutoff30d; });
      safeSetItem('colere_completions', JSON.stringify(completions));
      // Compteur zone rouge (shadid)
      if (_colereMode === 'shadid') {
        var _zrc = parseInt(safeGetItem('colere_zone_rouge_count') || '0', 10);
        safeSetItem('colere_zone_rouge_count', String(_zrc + 1));
      }
      // Compter sur 7 jours
      var cutoff7d = Date.now() - 7 * 86400000;
      var recent = completions.filter(function(t) { return t > cutoff7d; });
      var lastSeen = parseInt(safeGetItem('colere_seuil_vu') || '0', 10);
      if (recent.length >= 5 && (Date.now() - lastSeen) > 30 * 86400000) {
        openColereSeuilTherapeute();
        return;
      }
    } catch(e) {}
    // Dépistage si 5+ Shadîd en 14j et pas encore fait
    if (_colereMode === 'shadid') {
      try {
        var sLog = JSON.parse(safeGetItem('itfaa_shadid_log') || '[]');
        sLog.push({ts:Date.now()});
        if (sLog.length > 50) sLog = sLog.slice(-50);
        safeSetItem('itfaa_shadid_log', JSON.stringify(sLog));
        var cut14 = Date.now() - 14 * 86400000;
        var r14 = sLog.filter(function(e) { return e.ts > cut14; });
        var depVu = parseInt(safeGetItem('itfaa_depistage_vu') || '0', 10);
        if (r14.length >= 5 && !safeGetItem('cure_depistage') && (Date.now() - depVu) > 30 * 86400000) {
          _itfaaDepistageEncart(); return;
        }
      } catch(e) {}
    }
  }
  renderBabAnNafs();
}

function openPorteSeuilTherapeute(porte) {
  var el = document.getElementById('babAnNafsContent');
  if (!el) return;
  var c = '#B33A3A';
  _hideAideBtn();
  var nb = document.getElementById('nav-bar-v2'); if (nb) nb.classList.remove('hidden-immersion');
  document.body.classList.add('in-bab-an-nafs');
  el.innerHTML = '<div style="padding:calc(var(--safe-top)+60px) 16px 120px;display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:60vh;text-align:center;">'
    + '<div style="font-family:var(--serif);font-size:20px;color:' + c + ';line-height:1.6;max-width:400px;margin:0 auto 24px;">Tu es revenu cinq fois cette semaine.</div>'
    + '<div class="itfaa-body" style="font-family:var(--serif);font-size:16px;line-height:1.8;max-width:400px;margin:0 auto 32px;">Allah voit ta lutte.<br>Cette porte t\u2019attend autant qu\u2019il faudra.<br><br>Et si la col\u00e8re continue de revenir aussi fort, parle \u00e0 un humain de confiance.</div>'
    + '<button onclick="safeSetItem(\'colere_seuil_vu\',String(Date.now()));_babImmersion=false;v2GoSanctuaire()" style="width:100%;max-width:320px;padding:16px;border-radius:12px;border:none;background:' + c + ';color:#000;font-size:16px;font-weight:600;font-family:var(--serif);cursor:pointer;">Continuer</button>'
    + '</div>';
}

