const DAY_LABELS = ['Lun','Mar','Mer','Jeu','Ven','Sam','Dim'];
function getWeeklyHadith(level) {
  const arr = WEEKLY_HADITHS[level];
  const weekNum = Math.floor(Date.now() / (7 * 24 * 3600 * 1000));
  return arr[weekNum % arr.length];
}
