var _regardeStream = null;

function _askCameraPermission(context) {
  return new Promise(function(resolve) {
    if (!navigator.permissions || !navigator.permissions.query) { resolve(true); return; }
    navigator.permissions.query({ name: 'camera' }).then(function(status) {
      if (status.state === 'granted') { resolve(true); return; }
      if (status.state === 'denied') {
        showToast(t('camera_denied'));
        resolve(false);
        return;
      }
      // 'prompt' — show explanation modal
      var _msg = context === 'regarde'
        ? 'Pour contempler ce que tes yeux ont vu. Cette photo ne quitte pas ton t\u00e9l\u00e9phone.'
        : 'Pour saisir l\u2019objet que tu offres \u00e0 ton intention du jour. Cet objet ne quitte pas ton t\u00e9l\u00e9phone.';
      var ov = document.createElement('div');
      ov.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(15,12,8,0.92);display:flex;align-items:center;justify-content:center;padding:24px;';
      ov.innerHTML = '<div style="text-align:center;max-width:320px;">'
        + '<div style="font-size:36px;margin-bottom:16px;">\uD83D\uDCF7</div>'
        + '<div style="font-family:\'Cormorant Garamond\',serif;font-size:20px;font-weight:700;color:#C8A84A;margin-bottom:12px;">Niyyah a besoin de ta cam\u00e9ra</div>'
        + '<div style="font-size:14px;color:rgba(240,234,214,0.75);line-height:1.6;margin-bottom:24px;">' + _msg + '</div>'
        + '<button id="_camContinue" style="padding:14px 28px;border:none;border-radius:24px;background:#C8A84A;color:#2C2E32;font-family:Cormorant Garamond,serif;font-size:15px;font-weight:700;cursor:pointer;margin-right:12px;">Continuer</button>'
        + '<button id="_camLater" style="padding:14px 20px;border-radius:24px;border:1px solid rgba(200,168,74,0.3);background:transparent;color:rgba(255,255,255,0.5);font-size:13px;cursor:pointer;">Plus tard</button>'
        + '</div>';
      document.body.appendChild(ov);
      document.getElementById('_camContinue').onclick = function() { ov.remove(); resolve(true); };
      document.getElementById('_camLater').onclick = function() { ov.remove(); resolve(false); };
    }).catch(function() { resolve(true); });
  });
}

async function regardeOpen() {
  _nAn('scanner_tab_visited');
  showAlHayaBtn();
  var screen = document.getElementById('regarde-screen');
  var content = document.getElementById('regarde-content');
  if (!screen || !content) return;
  closeRegardeJournal();
  closeRegardeDetail();
  if (typeof closeNiyyahJournal === 'function') closeNiyyahJournal();
  if (typeof closeNiyyahDetail === 'function') closeNiyyahDetail();

  // Charger regard-library AVANT d'activer la capture
  if (!window.REGARD_VERSETS) {
    try {
      var _rlRes = await fetch('./data/regard-library.json');
      var _rlData = await _rlRes.json();
      var _rlNorm = {};
      Object.keys(_rlData).forEach(function(k) { _rlNorm[k.toUpperCase()] = _rlData[k]; });
      window.REGARD_VERSETS = _rlNorm;
    } catch(e) {}
    window._regardLibLoading = false;
  }

  // Pré-écran permission caméra
  var _camOk = await _askCameraPermission('regarde');
  if (!_camOk) return;

  // Init caméra
  try {
    _regardeStream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }
    });
    content.innerHTML = '<video id="regarde-video" autoplay playsinline muted style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;"></video>'
      + '<div style="position:absolute;bottom:140px;left:50%;transform:translateX(-50%);z-index:5;text-align:center;font-family:var(--serif);font-size:12px;letter-spacing:0.2em;text-transform:uppercase;color:rgba(212,175,55,0.85);text-shadow:0 1px 4px rgba(0,0,0,0.8);background:rgba(0,0,0,0.4);padding:6px 12px;border-radius:16px;">'+t('regarde_hint')+'</div>'
      + '<button id="regarde-capture-btn" onclick="regardeCapture()" style="position:absolute;bottom:40px;left:50%;transform:translateX(-50%);z-index:10;width:80px;height:80px;border-radius:50%;border:3px solid #C8A84A;background:rgba(200,168,75,0.15);cursor:pointer;display:flex;align-items:center;justify-content:center;"><div style="width:62px;height:62px;border-radius:50%;background:linear-gradient(135deg,#D4AF37,#B8940A);pointer-events:none;"></div></button>';
    var video = document.getElementById('regarde-video');
    video.srcObject = _regardeStream;
    await video.play();
  } catch(e) {
    content.innerHTML = '<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;gap:16px;"><div style="font-family:\'Cormorant Garamond\',serif;font-size:16px;font-style:italic;color:#C8A84A;text-align:center;padding:40px;">' + t('camera_denied') + '</div><button onclick="regardeOpen()" style="padding:10px 24px;border-radius:12px;border:1px solid rgba(200,168,75,0.3);background:transparent;color:#C8A84A;font-size:13px;cursor:pointer;">' + t('btn_retry') + '</button></div>';
  }

  screen.classList.add('active');
  document.body.style.overflow = 'hidden';
}

