function getRitualItems(prayer) {
  if (!Array.isArray(LEVELS)) return [];
  var _motiv = getEffectiveMotiv();
  const items = [];
  const alwaysItems = [];
  [0,1].forEach(i => {
    const lvl = LEVELS[i];
    if (!lvl || !lvl.sections) return;
    lvl.sections.forEach(s => {
      (s.items || []).forEach(it => {
        if (it.id === prayer) return;
        if (_motiv && it.paths && !it.paths.includes(_motiv)) return;
        if (it.alwaysVisible) { alwaysItems.push(it); return; }
        var _bm = Array.isArray(it.block) ? it.block.includes(prayer) : (it.block === prayer);
        if (_bm || it.block === 'jour') {
          items.push(it);
        }
      });
    });
  });
  items.push(...alwaysItems);
  var _ritualOrder = {
    fajr: ['sunnah_fajr','istighfar','allahumma_salam','tasbih','ayat_kursi','muawwidhat','wird_matin'],
    dhuhr: ['istighfar','allahumma_salam','tasbih','ayat_kursi','muawwidhat','sunnah_prieres','wird_matin'],
    asr: ['istighfar','allahumma_salam','tasbih','ayat_kursi','muawwidhat'],
    maghrib: ['istighfar','allahumma_salam','tasbih','ayat_kursi','muawwidhat','wird_soir'],
    isha: ['istighfar','allahumma_salam','tasbih','ayat_kursi','muawwidhat','witr','wird_soir']
  };
  var _order = _ritualOrder[prayer];
  if (_order) {
    items.sort(function(a, b) {
      var ai = _order.indexOf(a.id), bi = _order.indexOf(b.id);
      if (ai === -1) ai = _order.length;
      if (bi === -1) bi = _order.length;
      return ai - bi;
    });
  }
  return items;
}
window.getRitualItems = getRitualItems;

function openVueRituel(prayer) {
  const v = document.getElementById('vue-rituel');
  if (!v) return;
  v.querySelector('.rituel-titre').textContent = 'APRÈS ' + prayer.toUpperCase();
  const next = { fajr:'Dhuhr', dhuhr:'Asr', asr:'Maghrib', maghrib:'Isha', isha:'Fajr' };
  v.querySelector('.rituel-prochaine').textContent = next[prayer] ? next[prayer].toUpperCase() + ' BIENTÔT' : '';
  const items = getRitualItems(prayer);
  const fridayIds = ['jumua','fri_kahf','fri_salawat','fri_doua'];
  const normalItems = items.filter(it => !fridayIds.includes(it.id));
  const main = v.querySelector('.rituel-content');
  const state = safeParseJSON('spiritual_v2', {});
  const renderItem = (it, vendredi) => {
    const done = state[it.id] ? 'done' : '';
    const ar = it.arabic ? '<div class="arabic">' + it.arabic + '</div>' : '';
    var _dhikrCount = '';
    if (it.id === 'tasbih' || it.id === 'istighfar') {
      var _sk = it.id === 'tasbih' ? 'tasbih_' + todayKey() + '_' + prayer : 'istighfar_' + todayKey();
      var _dc = 0;
      try { var _dr = JSON.parse(localStorage.getItem(_sk) || '{}'); if (_dr.date === todayKey()) _dc = _dr.count || 0; } catch(e) {}
      _dhikrCount = '<div style="font-size:12px;font-style:italic;color:#C8A84A;margin-top:2px;">' + (_dc >= 100 ? '100 \u2713' : _dc + ' / 100') + '</div>';
    }
    const sub = it.sub ? '<div class="sub">' + it.sub + '</div>' : '';
    const audio = it.audio ? '<button class="btn-audio" data-audio-id="' + it.id + '" onclick="event.stopPropagation();playAudioById(this)">\u{1F50A}</button>' : '';
    const cls = vendredi ? 'rituel-item vendredi ' : 'rituel-item ';
    const tog = (vendredi && it.id !== 'jumua') ? 'toggleFridayItem' : 'toggleItem';
    const _click = it.id === 'tasbih' ? 'openTasbihModal(\'' + prayer + '\');'
      : it.id === 'istighfar' ? 'openIstighfarModal();'
      : tog + '(\'' + it.id + '\',event); openVueRituel(\'' + prayer + '\');';
    var _dhikrSvg = '<svg width="22" height="22" viewBox="0 0 22 22" fill="none" stroke="#C8A84A" stroke-width="1.5" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><circle cx="11" cy="11" r="2" fill="#C8A84A" stroke="none"/><line x1="11" y1="1.5" x2="11" y2="3"/></svg>';
    var _dhikrBtn = (it.id === 'tasbih') ? '<button style="background:none;border:none;cursor:pointer;flex-shrink:0;padding:4px;" onclick="event.stopPropagation();openTasbihModal(\'' + prayer + '\');">' + _dhikrSvg + '</button>'
      : (it.id === 'istighfar') ? '<button style="background:none;border:none;cursor:pointer;flex-shrink:0;padding:4px;" onclick="event.stopPropagation();openIstighfarModal();">' + _dhikrSvg + '</button>' : '';
    return '<div class="' + cls + done + '" id="rituel-item-' + it.id + '" onclick="' + _click + '"><div class="check"></div><div style="flex:1"><div class="label">' + (it.label||it.id) + '</div>' + _dhikrCount + sub + ar + '</div>' + audio + _dhikrBtn + '</div>';
  };
  let html = '';
  // Bandeau prière avec toggles
  const _onTime = !!state[prayer + '_ontime'];
  const _atMosq = !!state[prayer + '_mosquee'];
  const _sw = 'width:32px;height:18px;border-radius:9px;display:flex;align-items:center;padding:2px;transition:background 0.2s;flex-shrink:0;';
  const _kn = 'width:14px;height:14px;border-radius:50%;transition:margin 0.2s;';
  const _atJum = !!state['dhuhr_jumua'];
  const _isJum = (prayer === 'dhuhr' && isFriday());
  var _prayerChecked = !!state[prayer];
  html += '<div style="display:flex;align-items:center;justify-content:space-between;padding:16px 18px;margin-bottom:16px;background:rgba(200,168,74,0.06);border:1px solid rgba(200,168,74,0.18);border-radius:14px;">'
    + '<div style="display:flex;align-items:center;gap:12px;cursor:pointer;" onclick="toggleItem(\'' + prayer + '\',event);openVueRituel(\'' + prayer + '\');">'
    + '<div class="check-circle" style="width:24px;height:24px;border-radius:50%;border:2px solid ' + (_prayerChecked ? '#C8A84A' : 'rgba(200,168,74,0.4)') + ';background:' + (_prayerChecked ? 'var(--gold-grad)' : 'transparent') + ';display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:all 0.25s;"><svg width="10" height="8" viewBox="0 0 12 10" fill="none" style="opacity:' + (_prayerChecked ? '1' : '0') + ';"><path d="M1 5L4.5 8.5L11 1" stroke="#000" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/></svg></div>'
    + '<div style="font-family:Cormorant Garamond,serif;font-size:17px;font-weight:600;color:#C8A84A;">' + prayer.charAt(0).toUpperCase() + prayer.slice(1) + ' accompli\u00a0?</div>'
    + '</div>'
    + '<div style="display:flex;gap:10px;align-items:center;opacity:' + (_prayerChecked ? '1' : '0.4') + ';transition:opacity 0.2s;">'
    + '<div style="display:flex;align-items:center;gap:4px;cursor:pointer;" onclick="togglePrayerOnTime(\'' + prayer + '\');openVueRituel(\'' + prayer + '\');">'
    + '<div style="font-size:11px;color:' + (_onTime ? 'var(--green)' : 'rgba(255,255,255,0.35)') + ';">\u23F0</div>'
    + '<div style="' + _sw + 'background:' + (_onTime ? 'var(--green)' : 'rgba(255,255,255,0.1)') + ';border:1px solid ' + (_onTime ? 'var(--green)' : 'rgba(255,255,255,0.15)') + ';">'
    + '<div style="' + _kn + 'background:' + (_onTime ? '#fff' : 'rgba(255,255,255,0.4)') + ';margin-left:' + (_onTime ? '14px' : '0') + ';"></div></div></div>'
    + (_isJum ? '' : '<div style="display:flex;align-items:center;gap:4px;cursor:pointer;" onclick="togglePrayerMosquee(\'' + prayer + '\');openVueRituel(\'' + prayer + '\');">'
    + '<div style="font-size:11px;color:' + (_atMosq ? '#C8A84A' : 'rgba(255,255,255,0.35)') + ';">\u{1F54C}</div>'
    + '<div style="' + _sw + 'background:' + (_atMosq ? '#C8A84A' : 'rgba(255,255,255,0.1)') + ';border:1px solid ' + (_atMosq ? '#C8A84A' : 'rgba(255,255,255,0.15)') + ';">'
    + '<div style="' + _kn + 'background:' + (_atMosq ? '#fff' : 'rgba(255,255,255,0.4)') + ';margin-left:' + (_atMosq ? '14px' : '0') + ';"></div></div></div>')
    + (_isJum ? '<div style="display:flex;align-items:center;gap:4px;cursor:pointer;" onclick="togglePrayerJumua();openVueRituel(\'' + prayer + '\');">'
    + '<div style="font-size:11px;color:' + (_atJum ? '#46B482' : 'rgba(255,255,255,0.35)') + ';">\u262A\uFE0F</div>'
    + '<div style="' + _sw + 'background:' + (_atJum ? '#46B482' : 'rgba(255,255,255,0.1)') + ';border:1px solid ' + (_atJum ? '#46B482' : 'rgba(255,255,255,0.15)') + ';">'
    + '<div style="' + _kn + 'background:' + (_atJum ? '#fff' : 'rgba(255,255,255,0.4)') + ';margin-left:' + (_atJum ? '14px' : '0') + ';"></div></div></div>' : '')
    + '</div></div>';
  if (isFriday()) {
    var _motivFri = getEffectiveMotiv();
    const fridayItems = FRIDAY_ITEMS_GLOBAL.filter(function(it) { return !_motivFri || !it.paths || it.paths.includes(_motivFri); });
    if (fridayItems.length) {
      html += '<div class="rituel-vendredi-sep"><span><div class="ar">\u0627\u0644\u062C\u064F\u0645\u064F\u0639\u064E\u0629</div><div class="fr">VENDREDI</div></span></div>';
      html += fridayItems.map(it => renderItem(it, true)).join('');
    }
  }
  var _renderOne = function(it) {
    return it.type === 'wird' ? renderWirdSmartCard(it, 0, undefined, prayer) : renderItem(it, false);
  };
  var _sortDone = function(arr) {
    arr.sort(function(a, b) { return (state[a.id] ? 1 : 0) - (state[b.id] ? 1 : 0); });
    return arr;
  };
  if (prayer === 'fajr') {
    var _avant = normalItems.filter(it => it.id === 'sunnah_fajr');
    var _apres = normalItems.filter(it => it.id !== 'sunnah_fajr');
    if (_avant.length) {
      html += '<div class="rituel-sep-avant"><span>AVANT LA PRIÈRE</span></div>';
      html += _avant.map(_renderOne).join('');
      html += '<div class="rituel-sep-avant"><span>APRÈS LA PRIÈRE</span></div>';
    }
    html += _sortDone(_apres).map(_renderOne).join('');
  } else {
    html += _sortDone(normalItems).map(_renderOne).join('');
  }
  main.innerHTML = html;
  document.getElementById('rituel-emblem').textContent = '\u0635\u0644\u0627\u0629';
  v.classList.remove('hidden');
}
