function getFilJourCardHTML() {
  const state = safeParseJSON('spiritual_v2', {});
  var _motivF = getEffectiveMotiv();
  var _passPath = function(it) { return !_motivF || !it.paths || it.paths.includes(_motivF); };
  let done = 0, total = 0;
  if (Array.isArray(LEVELS)) {
    [2,3].forEach(i => {
      const lvl = LEVELS[i];
      if (!lvl || !lvl.sections) return;
      lvl.sections.forEach(s => {
        (s.items || []).forEach(it => {
          if (!_passPath(it)) return;
          total++; if (state[it.id]) done++;
        });
      });
    });
    [0,1].forEach(i => {
      var lvl = LEVELS[i];
      if (!lvl || !lvl.sections) return;
      lvl.sections.forEach(s => {
        (s.items || []).forEach(it => {
          if (!it.filDuJour || !_passPath(it)) return;
          total++; if (state[it.id]) done++;
        });
      });
    });
  }
  return '<div class="fil-jour-connector">\u2014 entre tes pri\u00e8res \u2014</div>'
    + '<div class="fil-jour-card" onclick="openVueAuFilDuJour()">'
    + '<div class="titre">AU FIL DU JOUR</div>'
    + '<div class="compteur"><span>' + (done === 0 ? 'La journ\u00e9e s\u2019\u00e9coule. Pose un geste.' : done <= 3 ? 'Tu as sem\u00e9. Continue.' : done <= 7 ? 'Belle travers\u00e9e du jour.' : 'Le jour est habit\u00e9.') + '</span></div>'
    + '</div>';
}
window.getFilJourCardHTML = getFilJourCardHTML;

function renderWirdAuFilDuJour(item) {
  var isMatin = item.session === 'matin';
  var label = isMatin ? 'Wird du Matin' : 'Wird du Soir';
  var arabic = isMatin ? '\u0648\u0650\u0631\u0652\u062F\u064F \u0627\u0644\u0635\u0651\u064E\u0628\u0627\u062D' : '\u0648\u0650\u0631\u0652\u062F\u064F \u0627\u0644\u0645\u064E\u0633\u0627\u0621';
  return '<div class="wird-fil-card" onclick="var r=document.getElementById(\'vue-rituel\');if(r)r.classList.add(\'hidden\');v2GoTo(\'wird\');">'
    + '<div class="wird-fil-body">'
    + '<div class="wird-fil-arabic">' + arabic + '</div>'
    + '<div class="wird-fil-label">' + label + '</div>'
    + '</div>'
    + '<div class="wird-fil-arrow">\u203A</div>'
    + '</div>';
}
window.renderWirdAuFilDuJour = renderWirdAuFilDuJour;

function openVueAuFilDuJour() {
  const v = document.getElementById('vue-rituel');
  if (!v) return;
  v.querySelector('.rituel-titre').textContent = 'AU FIL DU JOUR';
  v.querySelector('.rituel-prochaine').textContent = '';
  v.querySelector('.rituel-poetique').textContent = 'Ce qui demeure entre tes pri\u00e8res.';
  var _motiv = getEffectiveMotiv();
  const items = [];
  if (Array.isArray(LEVELS)) {
    var _dayOfWeek = new Date().getDay();
    [2,3].forEach(i => {
      const lvl = LEVELS[i];
      if (!lvl || !lvl.sections) return;
      lvl.sections.forEach(s => {
        (s.items || []).forEach(it => {
          if (_motiv && it.paths && !it.paths.includes(_motiv)) return;
          if (it.id === 'sunnah_jejune' && _dayOfWeek !== 1 && _dayOfWeek !== 4) return;
          items.push(it);
        });
      });
    });
  }
  [0,1].forEach(i => {
    var lvl = LEVELS[i];
    if (!lvl || !lvl.sections) return;
    lvl.sections.forEach(s => {
      (s.items || []).forEach(it => {
        if (!it.filDuJour) return;
        if (_motiv && it.paths && !it.paths.includes(_motiv)) return;
        if (it.id === 'sunnah_jejune' && _dayOfWeek !== 1 && _dayOfWeek !== 4) return;
        items.push(it);
      });
    });
  });
  const main = v.querySelector('.rituel-content');
  const state = safeParseJSON('spiritual_v2', {});
  var _catOrder = [
    { key: 'rituels', title: 'RITUELS DU JOUR', icon: '\uD83D\uDD4B', defaultOpen: true },
    { key: 'science', title: 'SCIENCE ET LECTURE', icon: '\uD83D\uDCD6', defaultOpen: false },
    { key: 'bienfaisance', title: 'BIENFAISANCE ET LIENS', icon: '\uD83D\uDC9B', defaultOpen: false },
    { key: 'duaa', title: "DOU'A ET TAFAKKUR", icon: '\uD83E\uDD32', defaultOpen: false }
  ];
  var _renderFilItem = function(it) {
    const done = state[it.id] ? 'done' : '';
    const ar = it.arabic ? '<div class="arabic">' + it.arabic + '</div>' : '';
    const sub = it.sub ? '<div class="sub">' + it.sub + '</div>' : '';
    const audio = it.audio ? '<button class="btn-audio" data-audio-id="' + it.id + '" onclick="event.stopPropagation();playAudioById(this)">🔊</button>' : '';
    var _knowledgeIds = ['savais_tu','fiqh_jour','hadith1','duaa_jour','vie_compagnons','vie_prophetes','quran_read','sira','podcast','recits_coran'];
    var _isKnowledgeFil = _knowledgeIds.indexOf(it.id) !== -1;
    var _coranBtn = it.coranPicker ? '<button class="btn-audio" onclick="event.stopPropagation();openCoranPicker(event)" style="font-size:12px;padding:4px 10px;width:auto;white-space:nowrap;font-family:\'Cormorant Garamond\',serif;color:#C8A84A;border:1px solid rgba(200,168,75,0.3);border-radius:8px;background:transparent;cursor:pointer;">\u00c9couter</button>' : '';
    var _filFlag = 'window._knowledgeFromFil=true;';
    var _click = it.id === 'sira' ? _filFlag + 'SIRA.openDetail();'
      : it.id === 'savais_tu' ? _filFlag + 'openVueSavaisTu();'
      : it.id === 'fiqh_jour' ? _filFlag + 'openVueFiqhJour();'
      : it.id === 'hadith1' ? _filFlag + 'openVueHadithJour();'
      : it.id === 'duaa_jour' ? _filFlag + 'openVueDuaaJour();'
      : it.id === 'vie_compagnons' ? _filFlag + 'openVueCompagnon();'
      : it.id === 'vie_prophetes' ? _filFlag + 'openVuePropheteJour();'
      : it.id === 'quran_read' ? _filFlag + 'openVueVersetJour();'
      : it.id === 'podcast' ? _filFlag + 'openPodcastPicker();'
      : it.id === 'recits_coran' ? _filFlag + 'openVueRecitsCoran();'
      : it.coranPicker ? 'openCoranPicker(event);'
      : 'toggleItem(\'' + it.id + '\',event); openVueAuFilDuJour();';
    var _readBtn = _isKnowledgeFil ? '<button style="background:none;border:none;cursor:pointer;flex-shrink:0;align-self:center;padding:8px 4px;margin:0;position:relative;z-index:10;isolation:isolate;" onclick="event.stopPropagation();' + _click + '"><svg width="14" height="22" viewBox="0 0 14 22" style="pointer-events:none;" aria-hidden="true"><path d="M3 4 L10 11 L3 18" fill="none" stroke="#C8A84A" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg></button>' : '';
    var _filKnBg = _isKnowledgeFil ? ' style="background:rgba(200,168,75,0.08);border-color:rgba(200,168,75,0.2);"' : '';
    var _checkClick = _isKnowledgeFil ? ' onclick="event.stopPropagation();toggleItem(\'' + it.id + '\',event);openVueAuFilDuJour();"' : '';
    return '<div class="rituel-item ' + done + '"' + _filKnBg + ' id="rituel-item-' + it.id + '" onclick="' + _click + '"><div class="check"' + _checkClick + '></div><div style="flex:1"><div class="label">' + (it.label||it.id) + '</div>' + sub + ar + '</div>' + _readBtn + _coranBtn + audio + '</div>';
  };
  var _html = '';
  _catOrder.forEach(function(cat) {
    var group = items.filter(function(it) { return it.category === cat.key; });
    if (!group.length) return;
    group.sort(function(a, b) { return (state[a.id] ? 1 : 0) - (state[b.id] ? 1 : 0); });
    var doneCount = group.filter(function(it) { return !!state[it.id]; }).length;
    var _openCat = safeGetItem('filjour_open_section');
    var isOpen = _openCat ? _openCat === cat.key : cat.defaultOpen;
    _html += '<div class="fil-acc" data-cat="' + cat.key + '">'
      + '<div class="fil-acc-header' + (isOpen ? ' open' : '') + '" onclick="toggleFilAccordion(\'' + cat.key + '\')">'
      + '<span class="fil-acc-icon">' + cat.icon + '</span>'
      + '<span class="fil-acc-title">' + cat.title + '</span>'
      + '<span class="fil-acc-count">' + doneCount + '/' + group.length + '</span>'
      + '<span class="fil-acc-chevron">\u25BE</span>'
      + '</div>'
      + '<div class="fil-acc-body" style="' + (isOpen ? '' : 'display:none;') + '">'
      + group.map(_renderFilItem).join('')
      + '</div></div>';
  });
  var _uncategorized = items.filter(function(it) { return !it.category; });
  if (_uncategorized.length) _html += _uncategorized.map(_renderFilItem).join('');
  main.innerHTML = _html;
  v.classList.remove('hidden');
  document.getElementById('rituel-emblem').textContent = '\u064A\u064E\u0648\u0652\u0645';
}
window.openVueAuFilDuJour = openVueAuFilDuJour;
function toggleFilAccordion(cat) {
  var all = document.querySelectorAll('.fil-acc');
  var clickedOpen = false;
  all.forEach(function(acc) {
    var h = acc.querySelector('.fil-acc-header');
    var b = acc.querySelector('.fil-acc-body');
    if (acc.dataset.cat === cat && !h.classList.contains('open')) {
      h.classList.add('open');
      b.style.display = '';
      clickedOpen = true;
    } else {
      h.classList.remove('open');
      b.style.display = 'none';
    }
  });
  safeSetItem('filjour_open_section', clickedOpen ? cat : '');
  if (clickedOpen) {
    var target = document.querySelector('.fil-acc[data-cat="' + cat + '"] .fil-acc-header');
    if (target) setTimeout(function() { target.scrollIntoView({ behavior: 'smooth', block: 'start' }); }, 220);
  }
}
window.toggleFilAccordion = toggleFilAccordion;

function playAudioById(btn) {
  const id = btn.dataset.audioId;
  if (!id || !Array.isArray(LEVELS)) return;
  let audioUrl = null;
  LEVELS.forEach(lvl => {
    if (!lvl || !lvl.sections) return;
    lvl.sections.forEach(s => {
      (s.items||[]).forEach(it => {
        if (it.id === id && it.audio) audioUrl = it.audio;
      });
    });
  });
  if (!audioUrl && Array.isArray(FRIDAY_ITEMS_GLOBAL)) {
    FRIDAY_ITEMS_GLOBAL.forEach(it => {
      if (it.id === id && it.audio) audioUrl = it.audio;
    });
  }
  if (audioUrl) playAudio(audioUrl, btn, event);
}
window.playAudioById = playAudioById;

