    var _rp = (rdv.partie && this.data && this.data.meta && this.data.meta.parties && this.data.meta.parties[rdv.partie]) ? this.data.meta.parties[rdv.partie] : null;
    var _rpt = (_rp && _rp.titre && _rp.titre.fr) ? _rp.titre.fr : '';
